input.oldString:
package workloadmanager

import (
	"context"
	"fmt"
	"time"

	"github.com/google/uuid"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SandboxManager struct {
	store store.Store
}

func NewSandboxManager() *SandboxManager {
	return &SandboxManager{
		store: store.Storage(),
	}
}

func (sm *SandboxManager) createSandbox(ctx context.Context, req *CreateSandboxRequest) (*types.SandboxInfo, error) {
	sessionID := uuid.New().String()
	now := time.Now()

	sandboxInfo := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        uuid.New().String(),
		SandboxNamespace: req.Namespace,
		Name:             fmt.Sprintf("%s-%s", req.Name, sessionID[:8]),
		SessionID:        sessionID,
		CreatedAt:        now,
		ExpiresAt:        now.Add(8 * time.Hour),
		Status:           "pending",
		EntryPoints:      []types.SandboxEntryPoint{},
	}

	if err := sm.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	klog.Infof("Created sandbox %s/%s for session %s", req.Namespace, sandboxInfo.Name, sessionID)

	return sandboxInfo, nil
}

func (sm *SandboxManager) deleteSandbox(ctx context.Context, sessionID string) error {
	sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return fmt.Errorf("session %s not found", sessionID)
		}
		return err
	}

	klog.Infof("Deleting sandbox %s/%s for session %s", sandbox.SandboxNamespace, sandbox.Name, sessionID)

	if err := sm.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return fmt.Errorf("failed to delete from store: %w", err)
	}

	return nil
}

func (sm *SandboxManager) getSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	return sm.store.GetSandboxBySessionID(ctx, sessionID)
}

