package workloadmanager

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/google/uuid"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SandboxManager struct {
	store          store.Store
	k8sClient      *K8sClient
	sandboxWatcher *SandboxWatcher
}

func NewSandboxManager(k8sClient *K8sClient) *SandboxManager {
	return &SandboxManager{
		store:          store.Storage(),
		k8sClient:      k8sClient,
		sandboxWatcher: NewSandboxWatcher(),
	}
}

func (sm *SandboxManager) createSandbox(ctx context.Context, req *CreateSandboxRequest) (*types.SandboxInfo, error) {
	sessionID := uuid.New().String()
	now := time.Now()
	sandboxName := fmt.Sprintf("%s-%s", req.Name, sessionID[:8])

	sandboxInfo := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        uuid.New().String(),
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		SessionID:        sessionID,
		CreatedAt:        now,
		ExpiresAt:        now.Add(8 * time.Hour),
		Status:           "pending",
		EntryPoints:      []types.SandboxEntryPoint{},
	}

	if err := sm.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	watcherKey := fmt.Sprintf("%s/%s", req.Namespace, sandboxName)
	watchCh := sm.sandboxWatcher.WatchOnce(watcherKey)
	defer sm.sandboxWatcher.StopWatching(watcherKey)

	var createdCR *unstructured.Unstructured
	var createErr error

	if req.Kind == types.AgentRuntimeKind {
		createdCR, createErr = sm.createAgentRuntimeSandbox(ctx, req, sandboxName)
	} else if req.Kind == types.CodeInterpreterKind {
		createdCR, createErr = sm.createCodeInterpreterSandbox(ctx, req, sandboxName)
	}

	if createErr != nil {
		sm.store.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, createErr
	}

	klog.Infof("Created sandbox CR %s/%s for session %s", req.Namespace, sandboxName, sessionID)

	select {
	case update := <-watchCh:
		if update.Status != "running" {
			sm.deleteK8sResource(ctx, req.Kind, req.Namespace, sandboxName)
			sm.store.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("sandbox reached non-running status: %s", update.Status)
		}

		podIP, err := sm.k8sClient.ResolvePodIP(req.Namespace, sandboxName)
		if err != nil {
			sm.deleteK8sResource(ctx, req.Kind, req.Namespace, sandboxName)
			sm.store.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("failed to resolve pod IP: %w", err)
		}

		ar, err := sm.k8sClient.GetAgentRuntime(req.Namespace, sandboxName)
		if err == nil {
			portsRaw, found, _ := unstructured.NestedSlice(ar.Object, "spec", "targetPort")
			if found {
				for _, p := range portsRaw {
					if portMap, ok := p.(map[string]interface{}); ok {
						portNum, _, _ := unstructured.NestedFloat64(portMap, "port")
						protocol, _, _ := unstructured.NestedString(portMap, "protocol")
						pathPrefix, _, _ := unstructured.NestedString(portMap, "pathPrefix")
						if protocol == "" {
							protocol = "HTTP"
						}
						sandboxInfo.EntryPoints = append(sandboxInfo.EntryPoints, types.SandboxEntryPoint{
							Path:     pathPrefix,
							Protocol: strings.ToLower(protocol),
							Endpoint: fmt.Sprintf("%s:%.0f", podIP, portNum),
						})
					}
				}
			}
		}

		if len(sandboxInfo.EntryPoints) == 0 {
			ci, err := sm.k8sClient.GetCodeInterpreter(req.Namespace, sandboxName)
			if err == nil {
				portsRaw, found, _ := unstructured.NestedSlice(ci.Object, "spec", "ports")
				if found {
					for _, p := range portsRaw {
						if portMap, ok := p.(map[string]interface{}); ok {
							portNum, _, _ := unstructured.NestedFloat64(portMap, "port")
							protocol, _, _ := unstructured.NestedString(portMap, "protocol")
							pathPrefix, _, _ := unstructured.NestedString(portMap, "pathPrefix")
							if protocol == "" {
								protocol = "HTTP"
							}
							sandboxInfo.EntryPoints = append(sandboxInfo.EntryPoints, types.SandboxEntryPoint{
								Path:     pathPrefix,
								Protocol: strings.ToLower(protocol),
								Endpoint: fmt.Sprintf("%s:%.0f", podIP, portNum),
							})
						}
					}
				}
			}
		}

		sandboxInfo.Status = "running"
		if err := sm.store.UpdateSandbox(ctx, sandboxInfo); err != nil {
			klog.Errorf("Failed to update sandbox with entry points: %v", err)
		}

		klog.Infof("Sandbox %s/%s is running with IP %s", req.Namespace, sandboxName, podIP)
		return sandboxInfo, nil

	case <-time.After(2 * time.Minute):
		sm.deleteK8sResource(ctx, req.Kind, req.Namespace, sandboxName)
		sm.store.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, fmt.Errorf("sandbox creation timed out")
	}
}

func (sm *SandboxManager) createAgentRuntimeSandbox(ctx context.Context, req *CreateSandboxRequest, sandboxName string) (*unstructured.Unstructured, error) {
	ar, err := sm.k8sClient.GetAgentRuntime(req.Namespace, req.Name)
	if err != nil {
		return nil, err
	}

	sandbox := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "agents.x-k8s.io/v1alpha1",
			"kind":       "Sandbox",
			"metadata": metav1.ObjectMeta{
				Name:      sandboxName,
				Namespace: req.Namespace,
				Labels: map[string]interface{}{
					"runtime.agentcube.io/sandbox-name": sandboxName,
					"runtime.agentcube.io/template":     req.Name,
				},
				Annotations: map[string]interface{}{
					"agents.x-k8s.io/sandbox-pod-name": sandboxName,
				},
			},
			"spec": map[string]interface{}{
				"template": map[string]interface{}{
					"spec": ar.Object["spec"],
				},
			},
		},
	}

	return sm.k8sClient.CreateSandbox(ctx, sandbox)
}

func (sm *SandboxManager) createCodeInterpreterSandbox(ctx context.Context, req *CreateSandboxRequest, sandboxName string) (*unstructured.Unstructured, error) {
	ci, err := sm.k8sClient.GetCodeInterpreter(req.Namespace, req.Name)
	if err != nil {
		return nil, err
	}

	sandbox := &unstructured.Unstructured{
		Object: map[string]interface{}{
			"apiVersion": "agents.x-k8s.io/v1alpha1",
			"kind":       "Sandbox",
			"metadata": metav1.ObjectMeta{
				Name:      sandboxName,
				Namespace: req.Namespace,
				Labels: map[string]interface{}{
					"runtime.agentcube.io/sandbox-name": sandboxName,
					"runtime.agentcube.io/template":     req.Name,
				},
				Annotations: map[string]interface{}{
					"agents.x-k8s.io/sandbox-pod-name": sandboxName,
				},
			},
			"spec": map[string]interface{}{
				"template": map[string]interface{}{
					"spec": ci.Object["spec"],
				},
			},
		},
	}

	return sm.k8sClient.CreateSandbox(ctx, sandbox)
}

func (sm *SandboxManager) deleteK8sResource(ctx context.Context, kind, namespace, name string) {
	deleteCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	if kind == types.AgentRuntimeKind {
		if err := sm.k8sClient.DeleteSandbox(deleteCtx, namespace, name); err != nil {
			klog.Errorf("Failed to delete sandbox %s/%s: %v", namespace, name, err)
		}
	} else if kind == types.CodeInterpreterKind {
		if err := sm.k8sClient.DeleteSandbox(deleteCtx, namespace, name); err != nil {
			klog.Errorf("Failed to delete sandbox %s/%s: %v", namespace, name, err)
		}
	}
}

func (sm *SandboxManager) deleteSandbox(ctx context.Context, sessionID string) error {
	sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return fmt.Errorf("session %s not found", sessionID)
		}
		return err
	}

	klog.Infof("Deleting sandbox %s/%s for session %s", sandbox.SandboxNamespace, sandbox.Name, sessionID)

	if err := sm.k8sClient.DeleteSandbox(ctx, sandbox.SandboxNamespace, sandbox.Name); err != nil {
		if !errors.IsNotFound(err) {
			return fmt.Errorf("failed to delete sandbox from K8s: %w", err)
		}
		klog.V(4).Infof("Sandbox %s/%s already deleted from K8s", sandbox.SandboxNamespace, sandbox.Name)
	}

	if err := sm.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return fmt.Errorf("failed to delete from store: %w", err)
	}

	return nil
}

func (sm *SandboxManager) getSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	return sm.store.GetSandboxBySessionID(ctx, sessionID)
}

