func (sm *SandboxManager) createSandbox(ctx context.Context, req *CreateSandboxRequest) (*types.SandboxInfo, error) {
	sessionID := uuid.New().String()
	now := time.Now()
	sandboxName := fmt.Sprintf("%s-%s", req.Name, sessionID[:8])

	sandboxInfo := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        uuid.New().String(),
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		SessionID:        sessionID,
		CreatedAt:        now,
		ExpiresAt:        now.Add(8 * time.Hour),
		Status:           "pending",
		EntryPoints:      []types.SandboxEntryPoint{},
	}

	if err := sm.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	watcherKey := fmt.Sprintf("%s/%s", req.Namespace, sandboxName)
	watchCh := sm.sandboxWatcher.WatchOnce(watcherKey)
	defer sm.sandboxWatcher.StopWatching(watcherKey)

	var createdCR *unstructured.Unstructured
	var createErr error

	if req.Kind == types.AgentRuntimeKind {
		createdCR, createErr = sm.createAgentRuntimeSandbox(ctx, req, sandboxName)
	} else if req.Kind == types.CodeInterpreterKind {
		createdCR, createErr = sm.createCodeInterpreterSandbox(ctx, req, sandboxName)
	}

	if createErr != nil {
		sm.store.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, createErr
	}

	klog.Infof("Created sandbox CR %s/%s for session %s", req.Namespace, sandboxName, sessionID)

	select {
	case update := <-watchCh:
		if update.Status != "running" {
			sm.deleteK8sResource(ctx, req.Kind, req.Namespace, sandboxName)
			sm.store.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("sandbox reached non-running status: %s", update.Status)
		}

		podIP, err := sm.k8sClient.ResolvePodIP(req.Namespace, sandboxName)
		if err != nil {
			sm.deleteK8sResource(ctx, req.Kind, req.Namespace, sandboxName)
			sm.store.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("failed to resolve pod IP: %w", err)
		}

