		if err == nil {
			portsRaw, found, _ := unstructured.NestedSlice(ar.Object, "spec", "targetPort")
			if found {
				for _, p := range portsRaw {
					if portMap, ok := p.(map[string]interface{}); ok {
						portNum, _, _ := unstructured.NestedFloat64(portMap, "port")
						protocol, _, _ := unstructured.NestedString(portMap, "protocol")
						pathPrefix, _, _ := unstructured.NestedString(portMap, "pathPrefix")
						if protocol == "" {
							protocol = "HTTP"
						}
						sandboxInfo.EntryPoints = append(sandboxInfo.EntryPoints, types.SandboxEntryPoint{
							Path:     pathPrefix,
							Protocol: strings.ToLower(protocol),
							Endpoint: fmt.Sprintf("%s:%.0f", podIP, portNum),
						})
					}
				}
			}
		}

		if len(sandboxInfo.EntryPoints) == 0 {
			ci, err := sm.k8sClient.GetCodeInterpreter(req.Namespace, sandboxName)
			if err == nil {
				portsRaw, found, _ := unstructured.NestedSlice(ci.Object, "spec", "ports")
				if found {
					for _, p := range portsRaw {
						if portMap, ok := p.(map[string]interface{}); ok {
							portNum, _, _ := unstructured.NestedFloat64(portMap, "port")
							protocol, _, _ := unstructured.NestedString(portMap, "protocol")
							pathPrefix, _, _ := unstructured.NestedString(portMap, "pathPrefix")
							if protocol == "" {
								protocol = "HTTP"
							}
							sandboxInfo.EntryPoints = append(sandboxInfo.EntryPoints, types.SandboxEntryPoint{
								Path:     pathPrefix,
								Protocol: strings.ToLower(protocol),
								Endpoint: fmt.Sprintf("%s:%.0f", podIP, portNum),
							})
						}
					}
				}
			}
		}

		sandboxInfo.Status = "running"
		if err := sm.store.UpdateSandbox(ctx, sandboxInfo); err != nil {
			klog.Errorf("Failed to update sandbox with entry points: %v", err)
		}

		klog.Infof("Sandbox %s/%s is running with IP %s", req.Namespace, sandboxName, podIP)
		return sandboxInfo, nil

	case <-time.After(2 * time.Minute):
