	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type ServerConfig struct {
	Port        int
	EnableAuth  bool
	EnableTLS   bool
	TLSCertFile string
	TLSKeyFile  string
	ReadTimeout time.Duration
	IdleTimeout time.Duration
}

type Server struct {
	config         *ServerConfig
	gin            *gin.Engine
	httpServer     *http.Server
	store          store.Store
	sandboxManager *SandboxManager
	startTime      time.Time
}

func NewServer(config *ServerConfig) (*Server, error) {
	if config.ReadTimeout == 0 {
		config.ReadTimeout = 15 * time.Second
	}
	if config.IdleTimeout == 0 {
		config.IdleTimeout = 90 * time.Second
	}

	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	s := &Server{
		config:         config,
		gin:            engine,
		store:          store.Storage(),
		sandboxManager: NewSandboxManager(),
		startTime:      time.Now(),
	}

	s.registerRoutes()

	if config.EnableAuth {
		if am, err := newAuthMiddleware(); err != nil {
			klog.Errorf("Failed to create auth middleware: %v", err)
		} else {
			s.gin.Use(func(c *gin.Context) {
				c.Set("authMiddleware", am)
			})
		}
	}

	return s, nil
}

func (s *Server) registerRoutes() {
	s.gin.GET("/health", s.handleHealth)

	v1 := s.gin.Group("/v1")
	v1.Use(loggingMiddleware)
	if s.config.EnableAuth {
		v1.Use(authMiddleware)
	}

	v1.POST("/agent-runtime", s.handleCreateAgentRuntime)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteAgentRuntime)
	v1.POST("/code-interpreter", s.handleCreateCodeInterpreter)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteCodeInterpreter)
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status": "healthy",
	})
}

func (s *Server) Start() error {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go s.startGarbageCollection(ctx)

	addr := fmt.Sprintf(":%d", s.config.Port)
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		return err
	}

	if err := s.store.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %w", err)
	}

	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     h2c.NewHandler(s.gin, &http2.Server{}),
		ReadTimeout: s.config.ReadTimeout,
		IdleTimeout: s.config.IdleTimeout,
	}

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigChan
		klog.Info("Received shutdown signal, shutting down gracefully...")
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 15*time.Second)
		defer shutdownCancel()

		if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
			klog.Errorf("HTTP server shutdown error: %v", err)
		}

		s.store.Close()
		cancel()
	}()

	klog.Infof("Workload Manager starting on %s", addr)

	if s.config.EnableTLS {
		if s.config.TLSCertFile == "" || s.config.TLSKeyFile == "" {
			return fmt.Errorf("TLS is enabled but cert/key not provided")
		}
		return s.httpServer.ServeTLS(listener, s.config.TLSCertFile, s.config.TLSKeyFile)
	}

	return s.httpServer.Serve(listener)
}

func (s *Server) startGarbageCollection(ctx context.Context) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			s.runGarbageCollection(ctx)
		}
	}
}

func (s *Server) runGarbageCollection(ctx context.Context) {
	gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	now := time.Now()
	inactiveCutoff := now.Add(-DefaultSandboxIdleTimeout)

	inactive, err := s.store.ListInactiveSandboxes(gcCtx, inactiveCutoff, 16)
	if err != nil {
		klog.Errorf("GC: failed to list inactive sandboxes: %v", err)
		return
	}

	expired, err := s.store.ListExpiredSandboxes(gcCtx, now, 16)
	if err != nil {
		klog.Errorf("GC: failed to list expired sandboxes: %v", err)
		return
	}

	sessionMap := make(map[string]bool)
	for _, sandbox := range inactive {
		sessionMap[sandbox.SessionID] = true
	}
	for _, sandbox := range expired {
		sessionMap[sandbox.SessionID] = true
	}

	for sessionID := range sessionMap {
		if err := s.sandboxManager.deleteSandbox(gcCtx, sessionID); err != nil {
			klog.Errorf("GC: failed to delete sandbox for session %s: %v", sessionID, err)
		} else {
			klog.V(4).Infof("GC: deleted sandbox for session %s", sessionID)
		}
	}
}

func (s *Server) handleCreateAgentRuntime(c *gin.Context) {
	s.handleCreateSandbox(c, "AgentRuntime")
}

func (s *Server) handleCreateCodeInterpreter(c *gin.Context) {
	s.handleCreateSandbox(c, "CodeInterpreter")
}

func (s *Server) handleCreateSandbox(c *gin.Context, kind string) {
	var sandboxReq CreateSandboxRequest
	if err := c.ShouldBindJSON(&sandboxReq); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"message": "Invalid request body",
		})
		return
	}

	sandboxReq.Kind = kind

	if err := sandboxReq.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"message": err.Error(),
		})
		return
	}

	ctx := c.Request.Context()

	sandboxInfo, err := s.sandboxManager.createSandbox(ctx, &sandboxReq)
	if err != nil {
		klog.Errorf("Failed to create sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{
			"message": "internal server error",
		})
		return
	}

	response := CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	}

	c.JSON(http.StatusOK, response)
}

func (s *Server) handleDeleteAgentRuntime(c *gin.Context) {
	s.handleDeleteSandbox(c, "AgentRuntime")
}

func (s *Server) handleDeleteCodeInterpreter(c *gin.Context) {
	s.handleDeleteSandbox(c, "CodeInterpreter")
}

func (s *Server) handleDeleteSandbox(c *gin.Context, kind string) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"message": "sessionId is required",
		})
		return
	}

	ctx := c.Request.Context()

	if err := s.sandboxManager.deleteSandbox(ctx, sessionID); err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"message": fmt.Sprintf("Session ID %s not found, maybe already deleted", sessionID),
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "Sandbox deleted successfully",
	})
}

