var (
	SandboxGVR = schema.GroupVersionResource{
		Group:    "agents.x-k8s.io",
		Version:  "v1alpha1",
		Resource: "sandboxes",
	}
	SandboxClaimGVR = schema.GroupVersionResource{
		Group:    "extensions.agents.x-k8s.io",
		Version:  "v1alpha1",
		Resource: "sandboxclaims",
	}
	AgentRuntimeGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "agentruntimes",
	}
	CodeInterpreterGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "codeinterpreters",
	}
)

type K8sClient struct {
	clientset       kubernetes.Interface
	dynamicClient   dynamic.Interface
	arInformer      cache.SharedIndexInformer
	ciInformer      cache.SharedIndexInformer
	podInformer     cache.SharedIndexInformer
	sandboxInformer cache.SharedIndexInformer
	mu              sync.RWMutex
}

func NewK8sClient() (*K8sClient, error) {
	config, err := getK8sConfig()
	if err != nil {
		return nil, err
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	arInformer := createInformer(dynamicClient, AgentRuntimeGVR)
	ciInformer := createInformer(dynamicClient, CodeInterpreterGVR)
	podInformer := createPodInformer(clientset)
	sandboxInformer := createSandboxInformer(dynamicClient)

	stopCh := make(chan struct{})
	arInformer.Run(stopCh)
	ciInformer.Run(stopCh)
	podInformer.Run(stopCh)
	sandboxInformer.Run(stopCh)

	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Minute)
	defer cancel()

	if !cache.WaitForCacheSync(ctx.Done(), arInformer.HasSynced, ciInformer.HasSynced, podInformer.HasSynced) {
		return nil, fmt.Errorf("failed to sync informers")
	}

	return &K8sClient{
		clientset:     clientset,
		dynamicClient: dynamicClient,
		arInformer:    arInformer,
		ciInformer:    ciInformer,
		podInformer:   podInformer,
	}, nil
}

func createInformer(dynClient dynamic.Interface, gvr schema.GroupVersionResource) cache.SharedIndexInformer {
	return cache.NewSharedIndexInformer(
		&cache.ListWatch{
			ListFunc: func(options metav1.ListOptions) (runtime.Object, error) {
				return dynClient.Resource(gvr).Namespace(corev1.NamespaceAll).List(context.Background(), options)
			},
			WatchFunc: func(options metav1.ListOptions) (watch.Interface, error) {
				return dynClient.Resource(gvr).Namespace(corev1.NamespaceAll).Watch(context.Background(), options)
			},
		},
		&unstructured.Unstructured{},
		30*time.Second,
		cache.Indexers{},
	)
}

func createPodInformer(clientset kubernetes.Interface) cache.SharedIndexInformer {
	return cache.NewSharedIndexInformer(
		&cache.ListWatch{
			ListFunc: func(options metav1.ListOptions) (runtime.Object, error) {
				return clientset.CoreV1().Pods(corev1.NamespaceAll).List(context.Background(), options)
			},
			WatchFunc: func(options metav1.ListOptions) (watch.Interface, error) {
				return clientset.CoreV1().Pods(corev1.NamespaceAll).Watch(context.Background(), options)
			},
		},
		&corev1.Pod{},
		30*time.Second,
		cache.Indexers{},
	)
}

func createSandboxInformer(dynClient dynamic.Interface) cache.SharedIndexInformer {
	return cache.NewSharedIndexInformer(
		&cache.ListWatch{
			ListFunc: func(options metav1.ListOptions) (runtime.Object, error) {
				return dynClient.Resource(SandboxGVR).Namespace(corev1.NamespaceAll).List(context.Background(), options)
			},
			WatchFunc: func(options metav1.ListOptions) (watch.Interface, error) {
				return dynClient.Resource(SandboxGVR).Namespace(corev1.NamespaceAll).Watch(context.Background(), options)
			},
		},
		&unstructured.Unstructured{},
		30*time.Second,
		cache.Indexers{},
	)
}

func getK8sConfig() (*rest.Config, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		loadingRules := clientcmd.NewDefaultClientConfigLoadingRules()
		configOverrides := &clientcmd.ConfigOverrides{}
		kubeConfig := clientcmd.NewNonInteractiveDeferredLoadingClientConfig(loadingRules, configOverrides)
		return kubeConfig.ClientConfig()
	}
	return config, nil
}

func (k *K8sClient) GetAgentRuntime(namespace, name string) (*unstructured.Unstructured, error) {
	obj, exists, err := k.arInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, name))
	if err != nil {
		return nil, err
	}
	if !exists {
		return nil, fmt.Errorf("agentruntime %s/%s not found", namespace, name)
	}
	return obj.(*unstructured.Unstructured), nil
}

func (k *K8sClient) GetCodeInterpreter(namespace, name string) (*unstructured.Unstructured, error) {
	obj, exists, err := k.ciInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, name))
	if err != nil {
		return nil, err
	}
	if !exists {
		return nil, fmt.Errorf("codeinterpreter %s/%s not found", namespace, name)
	}
	return obj.(*unstructured.Unstructured), nil
}

func (k *K8sClient) ResolvePodIP(namespace, sandboxName string) (string, error) {
	k.mu.RLock()
	defer k.mu.RUnlock()

	obj, exists, err := k.podInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, sandboxName))
	if err != nil {
		return "", err
	}

	if !exists {
		allPods, err := k.podInformer.GetIndexer().ByIndex("", "")
		if err != nil {
			allPods = k.podInformer.GetIndexer().List()
		}
		for _, p := range allPods {
			pod := p.(*corev1.Pod)
			if pod.GetLabels()["runtime.agentcube.io/sandbox-name"] == sandboxName {
				obj = pod
				exists = true
				break
			}
		}
	}

	if !exists {
		return "", fmt.Errorf("pod not found for sandbox %s", sandboxName)
	}

	pod := obj.(*corev1.Pod)
	if pod.Status.Phase != corev1.PodRunning || pod.Status.PodIP == "" {
		return "", fmt.Errorf("pod %s is not running or has no IP", sandboxName)
	}

	return pod.Status.PodIP, nil
}

func (k *K8sClient) CreateSandbox(ctx context.Context, sandbox *unstructured.Unstructured) (*unstructured.Unstructured, error) {
	namespace := sandbox.GetNamespace()
	if namespace == "" {
		namespace = corev1.NamespaceDefault
	}
	return k.dynamicClient.Resource(SandboxGVR).Namespace(namespace).Create(ctx, sandbox, metav1.CreateOptions{})
}

func (k *K8sClient) CreateSandboxClaim(ctx context.Context, claim *unstructured.Unstructured) (*unstructured.Unstructured, error) {
	namespace := claim.GetNamespace()
	if namespace == "" {
		namespace = corev1.NamespaceDefault
	}
	return k.dynamicClient.Resource(SandboxClaimGVR).Namespace(namespace).Create(ctx, claim, metav1.CreateOptions{})
}

func (k *K8sClient) DeleteSandbox(ctx context.Context, namespace, name string) error {
	err := k.dynamicClient.Resource(SandboxGVR).Namespace(namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return err
	}
	return nil
}

func (k *K8sClient) DeleteSandboxClaim(ctx context.Context, namespace, name string) error {
	err := k.dynamicClient.Resource(SandboxClaimGVR).Namespace(namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return err
	}
	return nil
}

func (k *K8sClient) AddSandboxWatchHandler(handler cache.ResourceEventHandler) {
	k.sandboxInformer.AddEventHandler(handler)
}

