func NewServer(config *Config) (*Server, error) {
	if config.Port == 0 {
		config.Port = 8080
	}

	if config.Workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			klog.Fatalf("Failed to get working directory: %v", err)
		}
		config.Workspace = wd
	}

