	if publicKeyStr == "" {
		klog.Fatalf("PICOD_AUTH_PUBLIC_KEY environment variable is required")
	}

	publicKey, err := parseRSAPublicKey(publicKeyStr)
	if err != nil {
		klog.Fatalf("Failed to parse public key: %v", err)
	}
	PublicKey = publicKey

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	s := &Server{
		config:    config,
		router:    router,
		startTime: StartTime,
